SELECT COUNT(*) as total_under_warranty
FROM cooling_products
WHERE warranty_status = 'Under Warranty';

SELECT warranty_status, COUNT(*) AS product_count
FROM cooling_products
GROUP BY warranty_status;

SELECT COUNT(*) AS number_of_products_under_warranty
FROM warranty_info
WHERE claim_status != 'Claimed' AND end_date IS NOT NULL;

SELECT product_number, cooling_capacity
FROM cooling_products
ORDER BY cooling_capacity DESC;

SELECT product_id, AVG(operational_hours) AS average_operational_hours
FROM cooling_products
GROUP BY product_id;

SELECT product_number, cooling_capacity, operational_hours
FROM cooling_products
ORDER BY cooling_capacity DESC;

SELECT cooling_capacity, operational_hours
FROM cooling_products
WHERE cooling_capacity = (SELECT MAX(cooling_capacity) FROM cooling_products);

SELECT product_id, COUNT(*) AS maintenance_count
FROM maintenance_schedule
GROUP BY product_id;
